if.then:
  %or = or i8 %x, %y
  %cmp = icmp eq i8 %or, 0
  ret i1 %cmp

if.else:
  ret i1 false
}

```
Expected optimized program:
```llvm
define i1 @test(i8 %x, i8 %y) {
entry:
  %cond = icmp ne i8 %x, %y
  br i1 %cond, label %if.then, label %if.else

if.then:
  ret i1 false

if.else:
  ret i1 false
}

```
